import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is simple interest?", a: "Simple interest is interest calculated only on the original principal amount, not on previously earned interest." },
  { q: "What is the simple interest formula?", a: "The simple interest formula is I = PRT, where I is interest, P is principal, R is the annual rate as a decimal, and T is time in years." },
  { q: "What is the difference between simple and compound interest?", a: "Simple interest grows by the same amount each period. Compound interest grows faster because interest earns additional interest over time." },
  { q: "Where is simple interest used in real life?", a: "Simple interest can appear in short-term loans, some auto loans, promissory notes, and classroom finance problems." },
  { q: "How do you calculate simple interest for days?", a: "Convert days into years by dividing by 365, then use I = PRT. For example, 90 days is about 90/365 years." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function compoundInterest(principal: number, rate: number, years: number) {
  return principal * Math.pow(1 + rate / 100 / 12, years * 12) - principal;
}

export default function SimpleInterestCalculator() {
  useCurrencyVersion();
  const [principal, setPrincipal] = useState(5000);
  const [rate, setRate] = useState(6);
  const [years, setYears] = useState(5);
  const result = useMemo(() => {
    const interest = principal * (rate / 100) * years;
    const finalAmount = principal + interest;
    const rows = Array.from({ length: Math.min(Math.max(1, Math.round(years * 12)), 360) }, (_, i) => {
      const month = i + 1;
      const monthlyInterest = principal * (rate / 100) / 12;
      return { month, interest: monthlyInterest, cumulative: monthlyInterest * month, balance: principal + monthlyInterest * month };
    });
    return { interest, finalAmount, rows };
  }, [principal, rate, years]);
  const comparison = [1, 2, 5, 10, 20, 30].map((period) => {
    const simple = 5000 * 0.06 * period;
    const compound = compoundInterest(5000, 6, period);
    return { period, simple, compound, difference: compound - simple };
  });

  return (
    <>
      <SEOHead title="Free Simple Interest Calculator Online - Calculate Simple Interest Instantly | CalcHive" description="Free online simple interest calculator. Calculate simple interest using I = PRT formula for any principal, rate and time period with monthly breakdown instantly. 100% free, no signup required." canonical="/simple-interest-calculator" keywords="free simple interest calculator, simple interest calculator online free, I=PRT calculator free, calculate simple interest free, simple vs compound interest calculator free" category="Financial Calculators" breadcrumbName="Free Simple Interest Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Simple Interest Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate simple interest using the I = PRT formula and compare it with compound interest.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Principal</label><input type="number" value={principal} onChange={(e) => setPrincipal(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Annual interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Time period (years)</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Simple Interest</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.interest)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Final amount</p><p className="text-lg font-extrabold text-foreground">{money(result.finalAmount)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Formula used</p><p className="text-lg font-extrabold text-foreground">I = PRT</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Simple Interest Using I = PRT for Free</h2><p className="text-muted-foreground leading-relaxed">Use I = PRT by multiplying principal by the annual rate as a decimal and the time in years. The final amount is principal plus interest.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1"><p>I = P  x  R  x  T</p><p>I = {money(principal)}  x  {(rate / 100).toFixed(4)}  x  {years}</p><p>I = {money(result.interest)}</p></div>
          <h2 className="text-2xl font-bold text-foreground">Simple Interest vs Compound Interest - What's the Difference</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Simple vs Compound Interest on $5,000 at 6%</caption><thead className="bg-muted/60"><tr>{["Period", "Simple Interest Earned", "Compound Interest Earned", "Difference", "Compound Advantage"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map((row) => <tr key={row.period}><td className="py-2.5 px-3 font-semibold">{row.period} years</td><td className="py-2.5 px-3">{money(row.simple)}</td><td className="py-2.5 px-3">{money(row.compound)}</td><td className="py-2.5 px-3">{money(row.difference)}</td><td className="py-2.5 px-3">{row.difference > 0 ? "Compound earns more" : "No advantage"}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Simple Interest Tool for Students and Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Monthly Breakdown Table</caption><thead className="bg-muted/60"><tr>{["Month", "Interest This Month", "Total Interest", "Final Amount"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{result.rows.map((row) => <tr key={row.month}><td className="py-2.5 px-3">{row.month}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{money(row.cumulative)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/simple-interest-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


